      "content": "const express = require('express');
const router = express.Router();
const { getTasksByStatus, updateTaskStatus } = require('./service');

// Get tasks by status
router.get('/:projectId/tasks', async (req, res) => {
  try {
    const tasks = await getTasksByStatus(req.params.projectId, req.query.status);
    if (!tasks || tasks.length === 0) return sendError(res, 404, 'E_NOTFOUND', 'No tasks found');
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'E_INTERNAL', error.message);
  }
});

// Update task status
router.patch('/:projectId/tasks/:taskId', async (req, res) => {
  if (!['todo', 'done'].includes(req.body.status)) return sendError(res, 400, 'E_BADREQUEST', 'Invalid status');
  try {
    const task = await updateTaskStatus(req.params.taskId, req.body.status);
    if (!task) return sendError(res, 404, 'E_NOTFOUND', 'Task not found');
    res.json({ task });
  } catch (error) {
    sendError(res, 500, 'E_INTERNAL', error.message);
  }
});

module.exports = router;
