      "content": "const tasks = require('./data'); // In-memory data store for simplicity

exports.getTasksByStatus = (projectId, status) => {
  return tasks.filter(t => t.projectId === projectId && t.status === status);
};

exports.updateTaskStatus = (taskId, newStatus) => {
  const taskIndex = tasks.findIndex(t => t.id === taskId);
  if (taskIndex === -1) return null;
  tasks[taskIndex].status = newStatus;
  return tasks[taskIndex];
};
